// Code Generated by Sidekick is for learning and experimentation purposes only.
/**
 * SPIC MACAY Dashboard JavaScript
 */

class SPICMacayDashboard {
    constructor() {
        this.apiBaseUrl = '/api';
        this.charts = {};
        this.init();
    }
    
    async init() {
        await this.loadStates();
        await this.loadDashboardStats();
        await this.loadEvents();
        this.initializeEventListeners();
    }
    
    async loadStates() {
        try {
            const response = await fetch(`${this.apiBaseUrl}/events/states`);
            const data = await response.json();
            
            if (data.success && data.states) {
                const stateFilter = document.getElementById('state-filter');
                data.states.forEach(state => {
                    const option = document.createElement('option');
                    option.value = state;
                    option.textContent = state;
                    stateFilter.appendChild(option);
                });
            }
        } catch (error) {
            console.error('Error loading states:', error);
        }
    }
    
    async loadDashboardStats() {
        try {
            const response = await fetch(`${this.apiBaseUrl}/dashboard/stats`);
            const data = await response.json();
            
            if (data.success) {
                this.updateStatsCards(data.stats);
                this.createCharts(data.stats);
            }
        } catch (error) {
            console.error('Error loading dashboard stats:', error);
        }
    }
    
    updateStatsCards(stats) {
        document.getElementById('total-events').textContent = stats.total_events || 0;
        document.getElementById('upcoming-events').textContent = stats.upcoming_events || 0;
        document.getElementById('current-fy-events').textContent = stats.current_fy_events || 0;
        
        // Count completed from events_by_status
        let completed = 0;
        if (stats.events_by_status) {
            stats.events_by_status.forEach(item => {
                if (item.event_status === 'Completed' || item.event_status === 'Performa APR Completed') {
                    completed += item.count;
                }
            });
        }
        
        document.getElementById('completed-events').textContent = completed;
    }
    
    createCharts(stats) {
        // Events by State Chart
        if (stats.events_by_state && stats.events_by_state.length > 0) {
            const stateCtx = document.getElementById('stateChart');
            if (!stateCtx) return;
            
            if (this.charts.stateChart) {
                this.charts.stateChart.destroy();
            }
            
            this.charts.stateChart = new Chart(stateCtx.getContext('2d'), {
                type: 'bar',
                data: {
                    labels: stats.events_by_state.map(item => item.state || 'Unknown'),
                    datasets: [{
                        label: 'Number of Events',
                        data: stats.events_by_state.map(item => item.count),
                        backgroundColor: 'rgba(139, 0, 0, 0.8)',
                        borderColor: 'rgba(139, 0, 0, 1)',
                        borderWidth: 1
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: true,
                    scales: {
                        y: {
                            beginAtZero: true,
                            ticks: {
                                stepSize: 1
                            }
                        }
                    },
                    plugins: {
                        legend: {
                            display: false
                        },
                        tooltip: {
                            callbacks: {
                                label: function(context) {
                                    return context.parsed.y + ' events';
                                }
                            }
                        }
                    }
                }
            });
        }
        
        // Events by Status Chart
        if (stats.events_by_status && stats.events_by_status.length > 0) {
            const statusCtx = document.getElementById('statusChart');
            if (!statusCtx) return;
            
            if (this.charts.statusChart) {
                this.charts.statusChart.destroy();
            }
            
            const statusColors = {
                'Pending': 'rgba(255, 193, 7, 0.8)',
                'Completed': 'rgba(40, 167, 69, 0.8)',
                'Cancelled': 'rgba(220, 53, 69, 0.8)',
                'Performa APR Completed': 'rgba(102, 126, 234, 0.8)',
                'Rejected': 'rgba(108, 117, 125, 0.8)'
            };
            
            this.charts.statusChart = new Chart(statusCtx.getContext('2d'), {
                type: 'doughnut',
                data: {
                    labels: stats.events_by_status.map(item => item.event_status),
                    datasets: [{
                        data: stats.events_by_status.map(item => item.count),
                        backgroundColor: stats.events_by_status.map(item => 
                            statusColors[item.event_status] || 'rgba(102, 126, 234, 0.8)'
                        ),
                        borderWidth: 2,
                        borderColor: '#fff'
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: true,
                    plugins: {
                        legend: {
                            position: 'bottom'
                        },
                        tooltip: {
                            callbacks: {
                                label: function(context) {
                                    const label = context.label || '';
                                    const value = context.parsed || 0;
                                    const total = context.dataset.data.reduce((a, b) => a + b, 0);
                                    const percentage = ((value / total) * 100).toFixed(1);
                                    return `${label}: ${value} (${percentage}%)`;
                                }
                            }
                        }
                    }
                }
            });
        }
        
        // Events by Module Chart
        if (stats.events_by_module && stats.events_by_module.length > 0) {
            const moduleCtx = document.getElementById('moduleChart');
            if (!moduleCtx) return;
            
            if (this.charts.moduleChart) {
                this.charts.moduleChart.destroy();
            }
            
            this.charts.moduleChart = new Chart(moduleCtx.getContext('2d'), {
                type: 'bar',
                data: {
                    labels: stats.events_by_module.map(item => item.module_name || 'Other'),
                    datasets: [{
                        label: 'Number of Events',
                        data: stats.events_by_module.map(item => item.count),
                        backgroundColor: 'rgba(220, 20, 60, 0.7)',
                        borderColor: 'rgba(220, 20, 60, 1)',
                        borderWidth: 1
                    }]
                },
                options: {
                    indexAxis: 'y',
                    responsive: true,
                    maintainAspectRatio: true,
                    scales: {
                        x: {
                            beginAtZero: true,
                            ticks: {
                                stepSize: 1
                            }
                        }
                    },
                    plugins: {
                        legend: {
                            display: false
                        }
                    }
                }
            });
        }
    }
    
    async loadEvents(filters = {}) {
        try {
            const queryParams = new URLSearchParams();
            
            if (filters.q) queryParams.append('q', filters.q);
            if (filters.status) queryParams.append('status', filters.status);
            if (filters.state) queryParams.append('state', filters.state);
            if (filters.date_from) queryParams.append('date_from', filters.date_from);
            if (filters.date_to) queryParams.append('date_to', filters.date_to);
            
            const response = await fetch(`${this.apiBaseUrl}/events/search?${queryParams}`);
            const data = await response.json();
            
            if (data.success) {
                this.displayEvents(data.events);
            }
        } catch (error) {
            console.error('Error loading events:', error);
            this.showEmptyState('Error loading events. Please try again.');
        }
    }
    
    displayEvents(events) {
        const tbody = document.getElementById('events-table-body');
        
        if (events.length === 0) {
            this.showEmptyState('No events found matching your criteria.');
            return;
        }
        
        tbody.innerHTML = events.map(event => `
            <tr>
                <td><strong>#${event.id}</strong></td>
                <td class="text-truncate" style="max-width: 200px;" title="${event.title || 'Untitled Event'}">
                    ${event.title || 'Untitled Event'}
                </td>
                <td>${event.artist_name || 'N/A'}</td>
                <td><small>${event.art_form || 'N/A'}</small></td>
                <td class="text-truncate" style="max-width: 150px;" title="${event.institution_name || 'N/A'}">
                    ${event.institution_name || 'N/A'}
                </td>
                <td><small>${this.formatDate(event.start_date)}</small></td>
                <td><small>${event.city || 'N/A'}, ${event.state || 'N/A'}</small></td>
                <td><span class="status-badge status-${this.getStatusClass(event.event_status)}">${event.event_status}</span></td>
                <td><small>${event.fy || 'N/A'}</small></td>
                <td>
                    <button class="btn btn-sm btn-outline-primary" onclick="viewEventDetails(${event.id})" title="View Details">
                        <i class="fas fa-eye"></i>
                    </button>
                </td>
            </tr>
        `).join('');
    }
    
    getStatusClass(status) {
        const statusMap = {
            'Pending': 'pending',
            'Completed': 'completed',
            'Cancelled': 'cancelled',
            'Performa APR Completed': 'completed',
            'Rejected': 'cancelled'
        };
        return statusMap[status] || 'pending';
    }
    
    showEmptyState(message) {
        const tbody = document.getElementById('events-table-body');
        tbody.innerHTML = `
            <tr>
                <td colspan="10" class="text-center py-5 text-muted">
                    <i class="fas fa-inbox fa-3x mb-3 d-block"></i>
                    <p>${message}</p>
                </td>
            </tr>
        `;
    }
    
    formatDate(dateString) {
        if (!dateString) return 'N/A';
        const date = new Date(dateString);
        return date.toLocaleDateString('en-IN', { 
            year: 'numeric', 
            month: 'short', 
            day: 'numeric' 
        });
    }
    
    initializeEventListeners() {
        // Search input - Enter key
        const searchInput = document.getElementById('search-input');
        if (searchInput) {
            searchInput.addEventListener('keypress', (e) => {
                if (e.key === 'Enter') {
                    this.searchEvents();
                }
            });
        }
    }
    
    searchEvents() {
        const filters = {
            q: document.getElementById('search-input').value,
            status: document.getElementById('status-filter').value,
            state: document.getElementById('state-filter').value,
            date_from: document.getElementById('date-from').value,
            date_to: document.getElementById('date-to').value
        };
        
        // Remove empty filters
        Object.keys(filters).forEach(key => {
            if (!filters[key]) delete filters[key];
        });
        
        this.loadEvents(filters);
    }
}

// Global functions
async function searchEvents() {
    if (window.dashboard) {
        window.dashboard.searchEvents();
    }
}

async function refreshEvents() {
    if (window.dashboard) {
        // Clear filters
        document.getElementById('search-input').value = '';
        document.getElementById('status-filter').value = '';
        document.getElementById('state-filter').value = '';
        document.getElementById('date-from').value = '';
        document.getElementById('date-to').value = '';
        
        await window.dashboard.loadEvents();
        await window.dashboard.loadDashboardStats();
    }
}

async function viewEventDetails(eventId) {
    try {
        const response = await fetch(`/api/events/${eventId}`);
        const data = await response.json();
        
        if (data.success) {
            const event = data.event;
            const modalBody = document.getElementById('eventModalBody');
            
            modalBody.innerHTML = `
                <div class="container-fluid">
                    <div class="row mb-3">
                        <div class="col-12">
                            <div class="alert alert-info">
                                <strong>Event ID:</strong> #${event.id} | 
                                <strong>APR Request ID:</strong> ${event.request_id || 'N/A'} |
                                <strong>Custom APR:</strong> ${event.custom_apr || 'N/A'}
                            </div>
                        </div>
                    </div>
                    
                    <div class="row">
                        <div class="col-md-6">
                            <h6 class="text-muted mb-3"><i class="fas fa-info-circle"></i> Event Information</h6>
                            <table class="table table-sm">
                                <tr>
                                    <td><strong>Title:</strong></td>
                                    <td>${event.title || 'N/A'}</td>
                                </tr>
                                <tr>
                                    <td><strong>Module:</strong></td>
                                    <td>${event.module_name || 'N/A'}</td>
                                </tr>
                                <tr>
                                    <td><strong>Date:</strong></td>
                                    <td>${event.start_date} ${event.end_date && event.end_date !== event.start_date ? 'to ' + event.end_date : ''}</td>
                                </tr>
                                <tr>
                                    <td><strong>Time:</strong></td>
                                    <td>${event.event_time || 'N/A'} ${event.end_time ? 'to ' + event.end_time : ''}</td>
                                </tr>
                                <tr>
                                    <td><strong>Venue:</strong></td>
                                    <td>${event.venue || 'N/A'}</td>
                                </tr>
                                <tr>
                                    <td><strong>Attendees:</strong></td>
                                    <td>${event.attendees || 'N/A'}</td>
                                </tr>
                                <tr>
                                    <td><strong>Budget:</strong></td>
                                    <td>${event.budget ? '₹' + event.budget : 'N/A'}</td>
                                </tr>
                                <tr>
                                    <td><strong>Status:</strong></td>
                                    <td><span class="status-badge status-${event.event_status.toLowerCase().replace(/ /g, '-')}">${event.event_status}</span></td>
                                </tr>
                                <tr>
                                    <td><strong>Financial Year:</strong></td>
                                    <td>${event.fy || 'N/A'}</td>
                                </tr>
                            </table>
                        </div>
                        
                        <div class="col-md-6">
                            <h6 class="text-muted mb-3"><i class="fas fa-user-tie"></i> Artist Details</h6>
                            <table class="table table-sm">
                                <tr>
                                    <td><strong>Artist:</strong></td>
                                    <td>${event.artist_name || 'N/A'}</td>
                                </tr>
                                <tr>
                                    <td><strong>Art Form:</strong></td>
                                    <td>${event.art_form || 'N/A'}</td>
                                </tr>
                                <tr>
                                    <td><strong>Email:</strong></td>
                                    <td>${event.artist_email || 'N/A'}</td>
                                </tr>
                                <tr>
                                    <td><strong>Phone:</strong></td>
                                    <td>${event.artist_phone || 'N/A'}</td>
                                </tr>
                                <tr>
                                    <td><strong>Accompanying:</strong></td>
                                    <td>${event.accompanying_artist || 'None'}</td>
                                </tr>
                            </table>
                            
                            <h6 class="text-muted mb-3 mt-4"><i class="fas fa-university"></i> Institution Details</h6>
                            <table class="table table-sm">
                                <tr>
                                    <td><strong>Institution:</strong></td>
                                    <td>${event.institution_name || 'N/A'}</td>
                                </tr>
                                <tr>
                                    <td><strong>City:</strong></td>
                                    <td>${event.institution_city || event.city || 'N/A'}</td>
                                </tr>
                                <tr>
                                    <td><strong>State:</strong></td>
                                    <td>${event.institution_state || event.state || 'N/A'}</td>
                                </tr>
                                <tr>
                                    <td><strong>Email:</strong></td>
                                    <td>${event.institution_email || 'N/A'}</td>
                                </tr>
                                <tr>
                                    <td><strong>Phone:</strong></td>
                                    <td>${event.institution_phone || 'N/A'}</td>
                                </tr>
                            </table>
                        </div>
                    </div>
                    
                    ${event.summary ? `
                    <div class="row mt-3">
                        <div class="col-12">
                            <h6 class="text-muted mb-2"><i class="fas fa-align-left"></i> Summary</h6>
                            <p class="text-muted">${event.summary}</p>
                        </div>
                    </div>
                    ` : ''}
                    
                    <div class="row mt-3">
                        <div class="col-12">
                            <small class="text-muted">
                                Added by: ${event.added_by || 'N/A'} on ${event.added_date || 'N/A'}
                                ${event.updated_by ? ' | Updated by: ' + event.updated_by + ' on ' + (event.updated_date || 'N/A') : ''}
                            </small>
                        </div>
                    </div>
                </div>
            `;
            
            const modal = new bootstrap.Modal(document.getElementById('eventModal'));
            modal.show();
        }
    } catch (error) {
        console.error('Error loading event details:', error);
        alert('Error loading event details. Please try again.');
    }
}

// Initialize dashboard when DOM is loaded
document.addEventListener('DOMContentLoaded', () => {
    window.dashboard = new SPICMacayDashboard();
});
